#import "UserInfoModel.h"

static UserInfoModel *shared = nil;
static NSString *loginStatus = @"";
static NSString *token = @"";
static BOOL debug = NO;

static NSString *accountType = @"1";
//static NSString *agencyId = @"";

@implementation UserInfoModel

+ (UserInfoModel *)shared {
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        shared = [[UserInfoModel alloc] init];
        if ([[NSUserDefaults standardUserDefaults] valueForKey:@"Login.Success"]) {
            loginStatus = [[NSUserDefaults standardUserDefaults] valueForKey:@"Login.Success"];
        }
        if ([[NSUserDefaults standardUserDefaults] valueForKey:@"Login.Token"]) {
            token = [[NSUserDefaults standardUserDefaults] valueForKey:@"Login.Token"];
        }
        //        if ([[NSUserDefaults standardUserDefaults] valueForKey:@"Login.AgencyId"]) {
        //            agencyId = [[NSUserDefaults standardUserDefaults] valueForKey:@"Login.AgencyId"];
        //        }
        if ([[NSUserDefaults standardUserDefaults] valueForKey:@"UserInfo"]) {
            shared.userInfo = [[NSUserDefaults standardUserDefaults] valueForKey:@"UserInfo"];
        }
        
        if ([[NSUserDefaults standardUserDefaults] valueForKey:@"UserInfoModel.Debug"]) {
            debug = [[NSUserDefaults standardUserDefaults] boolForKey:@"UserInfoModel.Debug"];
        }
        
        if ([[NSUserDefaults standardUserDefaults] valueForKey:@"UserInfoModel.AccountType"]) {
            accountType = [[NSUserDefaults standardUserDefaults] valueForKey:@"UserInfoModel.AccountType"];
        }
        
    });
    return shared;
}

- (BOOL)isLogin {
    return ![loginStatus isEqualToString:@""] && loginStatus.length > 0;
}

+ (BOOL)isHTTPS {
    return debug;
}

- (void)setAccountType:(NSString *)type {
    accountType = type;
    [[NSUserDefaults standardUserDefaults] setObject:type forKey:@"UserInfoModel.AccountType"];
    [[NSUserDefaults standardUserDefaults] synchronize];
}

- (NSString *)getAccountType {
    return accountType;
}

- (void)setLogin:(BOOL)login {
    if (login) {
        //登录
        loginStatus = @"loign";
        [[NSUserDefaults standardUserDefaults] setObject:@"login" forKey:@"Login.Success"];
    } else {
        //退出登录
        loginStatus = @"";
        token = @"";
        [[NSUserDefaults standardUserDefaults] removeObjectForKey:@"UserInfo"];
        [[NSUserDefaults standardUserDefaults] removeObjectForKey:@"Login.Success"];
        [[NSUserDefaults standardUserDefaults] removeObjectForKey:@"Login.Token"];
        [[NSUserDefaults standardUserDefaults] synchronize];
    }
    [[NSNotificationCenter defaultCenter] postNotificationName:@"LoginSucess" object:nil];
}

- (void)userLogout {
    NSString *url = [NSString stringWithFormat:@"%@/userLogout", baseUrl];
    [[NetworkingManager manager] postDataWithUrl:url parameters:nil success:^(id json) {
        [[UserInfoModel shared] setLogin:NO];
    } failure:nil];
}

- (NSString *)loginToken {
    return token;
}

- (void)setLoginToken:(NSString *)loginToken {
    token = loginToken;
    [[NSUserDefaults standardUserDefaults] setValue: loginToken forKey:@"Login.Token"];
    [[NSUserDefaults standardUserDefaults] synchronize];
}

- (NSString *)agencyId {
    return self.userInfo[@"agencyId"];
}

- (void)setUserInfo:(NSDictionary *)userInfo {
    NSString *nickname = [NSString nullToString:userInfo[@"nickname"]];
    NSMutableDictionary *tmp = [[NSMutableDictionary alloc] initWithDictionary:userInfo];
    tmp[@"nickname"] = nickname;
    _userInfo = tmp;
    [[NSUserDefaults standardUserDefaults] setObject:_userInfo forKey:@"UserInfo"];
    [[NSUserDefaults standardUserDefaults] synchronize];
}

