+ (void)requestInfo:(_Nullable RequestCompleteBlock)block{
    NSString *url = [NSString stringWithFormat:@"%@/userInfo", baseUrl];
    [[NetworkingManager manager] postDataWithUrl:url parameters:nil success:^(id json) {
        NSDictionary *data = json[@"data"];
        if (data) {
            NSInteger status = [data[@"status"] integerValue];
            if (status == 1) {
                [SVProgressHUD showErrorWithStatus:@"您的账户已被封禁，请联系客服"];
                [[UserInfoModel shared] setLogin:NO];
                return;
            }
            [UserInfoModel shared].userInfo = data;
            if (block) {
                block(data);
            }
        }
    } failure:nil];
}

+ (BOOL)checkHTTPEnable {
    NSDictionary *proxySettings =  (__bridge NSDictionary *)(CFNetworkCopySystemProxySettings());
    NSArray *proxies = (__bridge NSArray *)(CFNetworkCopyProxiesForURL((__bridge CFURLRef _Nonnull)([NSURL URLWithString:@"http://www.baidu.com"]), (__bridge CFDictionaryRef _Nonnull)(proxySettings)));
    NSDictionary *settings = [proxies objectAtIndex:0];
    
    if ([[settings objectForKey:(NSString *)kCFProxyTypeKey] isEqualToString:@"kCFProxyTypeNone"]){
        //没有设置代理
        return NO;
    }else{
        //设置代理了
        return YES;
    }
}

+ (NSString *)userLevel:(NSInteger)level {
    switch (level) {
        case 1:
            return @"一级代理";
            break;
        case 2:
            return @"二级代理";
            break;
        case 3:
            return @"三级代理";
            break;
        case 4:
            return @"四级代理";
            break;
        case 5:
            return @"五级代理";
            break;
        case 6:
            return @"六级代理";
            break;
        case 7:
            return @"七级代理";
            break;
        case 8:
            return @"八级代理";
            break;
        case 9:
            return @"九级代理";
            break;
        case 10:
            return @"";
            break;
        default:
            return @"";
            break;
    }
}

+ (NSString *)qrCdoe {
    NSString *qrCode = @"data:image/png;base64,";
    return qrCode;
}


@end
